let lastSubmittedValues = null;

async function submitForm() {
    const departure = document.getElementById('departure').value;
    const destination = document.getElementById('destination').value;
    const time = document.getElementById('time').value;

    // Prevent redundant API calls with the same input
    if (lastSubmittedValues && 
        lastSubmittedValues.departure === departure &&
        lastSubmittedValues.destination === destination &&
        lastSubmittedValues.time === time) {
        return;
    }

    try {
        const apiUrl = `https://busapi.amithv.xyz/api/v1/schedules?departure=${encodeURIComponent(departure)}&destination=${encodeURIComponent(destination)}`;
        const response = await fetch(apiUrl);
        const scheduleData = await response.json();
        updateSchedule(scheduleData, departure, destination, time);
    } catch (error) {
        console.error("Error fetching data:", error);
    }

    lastSubmittedValues = { departure, destination, time };
}

function updateSchedule(scheduleData, departure, destination, time) {
    const scheduleContainer = document.getElementById("scheduleContainer");
    scheduleContainer.innerHTML = "";

    if (!scheduleData || scheduleData.length === 0) {
        showNoResults();
        return;
    }

    scheduleData.forEach(trip => {
        renderVehicleAndStations(trip, departure, destination, time);
    });
}

function renderVehicleAndStations(trip, departure, destination, time) {
    const vehicleDiv = document.createElement("div");
    vehicleDiv.textContent = `Vehicle Number: ${trip.vehicle_number}, Trip: ${trip.trip}`;
    document.getElementById("scheduleContainer").appendChild(vehicleDiv);

    trip.stations.forEach((station, index) => {
        const stationDiv = createStationElement(station, index, trip, departure, destination, time);
        document.getElementById("scheduleContainer").appendChild(stationDiv);
    });
}

function createStationElement(station, index, trip, departure, destination, time) {
    const stationDiv = document.createElement("div");
    stationDiv.classList.add("station");

    const arrivalTimeDiv = createTimeElement(station.arrivalTime, "arrival", trip, index, departure, destination, time);
    stationDiv.appendChild(arrivalTimeDiv);

    const hoiDiv = createHoiElement(trip, index, departure, destination, time);
    stationDiv.appendChild(hoiDiv);

    const stationNameDiv = document.createElement("div");
    stationNameDiv.classList.add("station-name");
    stationNameDiv.textContent = station.station;
    stationDiv.appendChild(stationNameDiv);

    const departureTimeDiv = createTimeElement(station.departureTime, "departure", trip, index, departure, destination, time);
    stationDiv.appendChild(departureTimeDiv);

    return stationDiv;
}

function createHoiElement(trip, index, departure, destination, time) {
    const hoiDiv = document.createElement("div");
    hoiDiv.classList.add("hoi");

    if (isTripActive(trip, index, departure, destination, time)) {
        hoiDiv.classList.add("green-border");
    }

    return hoiDiv;
}

function createTimeElement(timeText, type, trip, index, departure, destination, time) {
    const timeWrapper = document.createElement("div");
    timeWrapper.classList.add("time-wrapper");

    const timeDiv = document.createElement("div");
    timeDiv.classList.add("station-time");

    if (isTripActive(trip, index, departure, destination, time)) {
        timeDiv.classList.add("green-bg");
    }

    timeDiv.textContent = timeText;
    timeWrapper.appendChild(timeDiv);

    if (index !== trip.stations.length - 1 && !isDestinationReached(trip, index, destination)) {
        const timelineDiv = document.createElement("div");
        timelineDiv.classList.add("timeline");

        if (isTripActive(trip, index, departure, destination, time)) {
            timelineDiv.classList.add("green-line");
        }

        timeWrapper.appendChild(timelineDiv);
    }

    return timeWrapper;
}

function isTripActive(trip, index, departure, destination, time) {
    const hasDeparted = trip.stations.some((s, i) => 
        s.station.toUpperCase().startsWith(departure) && i <= index
    );
    const hasArrived = trip.stations.some((s, i) => 
        s.station.toUpperCase().startsWith(destination) && i >= index
    );

    return hasDeparted && !hasArrived;
}

function isDestinationReached(trip, index, destination) {
    return trip.stations[index].station.toUpperCase().startsWith(destination);
}

function showNoResults() {
    const noResults = document.getElementById("no-results");
    noResults.style.display = "block";
}
